import com.fasterxml.jackson.databind.ObjectMapper;

public class SecureDeserializationExample {

    public static void main(String[] args) {
        String userInput = "{\"name\": \"John Doe\", \"age\": 30}";

        // Deserialize the JSON string
        ObjectMapper objectMapper = new ObjectMapper();
        try {
            Person person = objectMapper.readValue(userInput, Person.class);
            System.out.println("Deserialized Person: " + person.getName() + ", " + person.getAge());
        } catch (Exception e) {
            System.out.println("Error deserializing input: " + e.getMessage());
        }
    }

    static class Person {
        private String name;
        private int age;

        public String getName() {
            return name;
        }

        public void setName(String name) {
            this.name = name;
        }

        public int getAge() {
            return age;
